import java.util.ArrayList;
import java.util.Arrays;

class Point implements Comparable<Point> {
    int x, y;
    Point(int x, int y) { this.x = x; this.y = y; }
    public int compareTo(Point other) {
        return this.x == other.x ? this.y - other.y : this.x - other.x;
    }
    public String toString() { return "(" + x + ", " + y + ")"; }
}

public class GrahamScan {
    static int orientation(Point p, Point q, Point r) {
        int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
        if (val == 0) return 0;
        return val > 0 ? 1 : 2;
    }

    static ArrayList<Point> grahamScan(Point[] points) {
        if (points.length < 3) return new ArrayList<>(Arrays.asList(points));
        Arrays.sort(points);
        Point bottom = points[0];
        Point[] remaining = Arrays.copyOfRange(points, 1, points.length);
        Arrays.sort(remaining, (a, b) -> {
            int dx1 = a.x - bottom.x, dx2 = b.x - bottom.x;
            int dy1 = a.y - bottom.y, dy2 = b.y - bottom.y;
            return dx1 == dx2 ? dy1 - dy2 : dx1 - dx2;
        });
        ArrayList<Point> stack = new ArrayList<>();
        stack.add(bottom);
        stack.add(remaining[0]);
        for (int i = 1; i < remaining.length; i++) {
            while (stack.size() > 1 && orientation(stack.get(stack.size() - 2), stack.get(stack.size() - 1), remaining[i]) != 2) {
                stack.remove(stack.size() - 1);
            }
            stack.add(remaining[i]);
        }
        return stack;
    }

    public static void main(String[] args) {
        Point[] points = {new Point(0, 0), new Point(1, 1), new Point(2, 0), new Point(2, 2), new Point(0, 2)};
        ArrayList<Point> result = grahamScan(points);
        System.out.println("Convex Hull: " + result);
    }
}
