using System;
using System.Collections.Generic;
using System.Linq;

class Point : IComparable<Point> {
    public int X { get; set; }
    public int Y { get; set; }
    public Point(int x, int y) { X = x; Y = y; }
    public int CompareTo(Point other) => X == other.X ? Y - other.Y : X - other.X;
    public override string ToString() => $"({X}, {Y})";
}

class Program {
    static int Orientation(Point p, Point q, Point r) {
        int val = (q.Y - p.Y) * (r.X - q.X) - (q.X - p.X) * (r.Y - q.Y);
        if (val == 0) return 0;
        return val > 0 ? 1 : 2;
    }

    static List<Point> GrahamScan(Point[] points) {
        if (points.Length < 3) return points.ToList();
        var sorted = points.OrderBy(p => p).ToArray();
        Point bottom = sorted[0];
        var remaining = sorted.Skip(1).OrderBy(p => (p.X - bottom.X, p.Y - bottom.Y)).ToArray();
        var stack = new List<Point> { bottom, remaining[0] };
        for (int i = 1; i < remaining.Length; i++) {
            while (stack.Count > 1 && Orientation(stack[stack.Count - 2], stack[stack.Count - 1], remaining[i]) != 2) {
                stack.RemoveAt(stack.Count - 1);
            }
            stack.Add(remaining[i]);
        }
        return stack;
    }

    static void Main() {
        Point[] points = { new Point(0, 0), new Point(1, 1), new Point(2, 0), new Point(2, 2), new Point(0, 2) };
        var result = GrahamScan(points);
        Console.WriteLine("Convex Hull: [" + string.Join(", ", result) + "]");
    }
}
// Çıxış: Convex Hull: [(0, 0), (2, 0), (2, 2), (0, 2)]

