std::vector<Point> grahamScan(std::vector<Point> points) {
    if (points.size() < 3) return points;
    std::sort(points.begin(), points.end());
    Point bottom = points[0];
    std::sort(points.begin() + 1, points.end(), [&bottom](const Point& a, const Point& b) {
        int dx1 = a.x - bottom.x, dx2 = b.x - bottom.x;
        int dy1 = a.y - bottom.y, dy2 = b.y - bottom.y;
        return dx1 == dx2 ? dy1 < dy2 : dx1 < dx2;
