int compare(const void* a, const void* b) {
    Point* p1 = (Point*)a;
    Point* p2 = (Point*)b;
    return p1->x == p2->x ? p1->y - p2->y : p1->x - p2->x;
}

int compareAngle(const void* a, const void* b, void* bottom) {
    Point* p1 = (Point*)a;
    Point* p2 = (Point*)b;
    Point* b = (Point*)bottom;
    int dx1 = p1->x - b->x, dx2 = p2->x - b->x;
    int dy1 = p1->y - b->y, dy2 = p2->y - b->y;
    return dx1 == dx2 ? dy1 - dy2 : dx1 - dx2;
}

Point* grahamScan(Point* points, int n, int* resultSize) {
    if (n < 3) {
        Point* result = (Point*)malloc(n * sizeof(Point));
        for (int i = 0; i < n; i++) result[i] = points[i];
        *resultSize = n;
        return result;
    }
    qsort(points, n, sizeof(Point), compare);
    Point bottom = points[0];
    qsort(points + 1, n - 1, sizeof(Point), (int (*)(const void*, const void*, void*))compareAngle, &bottom);
    Point* stack = (Point*)malloc(n * sizeof(Point));
    int top = 2;
    stack[0] = bottom;
    stack[1] = points[1];
    for (int i = 2; i < n; i++) {
        while (top > 1 && orientation(stack[top - 2], stack[top - 1], points[i]) != 2) {
            top--;
        }
        stack[top++] = points[i];
    }
    *resultSize = top;
    return stack;
}

