    static int Orientation(Point p, Point q, Point r) {
        int val = (q.Y - p.Y) * (r.X - q.X) - (q.X - p.X) * (r.Y - q.Y);
        if (val == 0) return 0;
        return val > 0 ? 1 : 2;
    }

    static List<Point> GrahamScan(Point[] points) {
        if (points.Length < 3) return points.ToList();
        var sorted = points.OrderBy(p => p).ToArray();
        Point bottom = sorted[0];
        var remaining = sorted.Skip(1).OrderBy(p => (p.X - bottom.X, p.Y - bottom.Y)).ToArray();
        var stack = new List<Point> { bottom, remaining[0] };
        for (int i = 1; i < remaining.Length; i++) {
            while (stack.Count > 1 && Orientation(stack[stack.Count - 2], stack[stack.Count - 1], remaining[i]) != 2) {
                stack.RemoveAt(stack.Count - 1);
            }
            stack.Add(remaining[i]);
        }
        return stack;
    }

    static void Main() {
